### 3.2 Deque — C Implementation (Input-Restricted, Array-Based)

```c
#include <stdio.h>
#define MAX 5

int deque[MAX];
int front = -1, rear = -1;

void insertRear(int x) {
    if ((rear + 1) % MAX == front) {
        printf("Deque is Full\n");
        return;
    }
    if (front == -1) {
        front = rear = 0;
    } else {
        rear = (rear + 1) % MAX;
    }
    deque[rear] = x;
    printf("Inserted %d at rear\n", x);
}

void deleteFront() {
    if (front == -1) {
        printf("Deque is Empty\n");
        return;
    }
    printf("Deleted %d from front\n", deque[front]);
    if (front == rear) {
        front = rear = -1;     // Reset to empty
    } else {
        front = (front + 1) % MAX;
    }
}

void deleteRear() {
    if (front == -1) {
        printf("Deque is Empty\n");
        return;
    }
    printf("Deleted %d from rear\n", deque[rear]);
    if (front == rear) {
        front = rear = -1;
    } else if (rear == 0) {
        rear = MAX - 1;        // Wrap around backwards
    } else {
        rear--;
    }
}

void display() {
    if (front == -1) {
        printf("Deque is Empty\n");
        return;
    }
    printf("Deque: ");
    int i = front;
    while (1) {
        printf("%d ", deque[i]);
        if (i == rear) break;
        i = (i + 1) % MAX;
    }
    printf("\n");
}

int main() {
    insertRear(10);
    insertRear(20);
    insertRear(30);
    display();
    deleteFront();
    deleteRear();
    display();
    return 0;
}
```

**Trace Table for `insertRear(10), insertRear(20), insertRear(30), deleteFront(), deleteRear()`:**

| Step | Operation | front | rear | Internal Array State | Visible Result |
|---|---|---|---|---|---|
| 1 | `insertRear(10)` | 0 | 0 | `[10, -, -, -, -]` | 10 added |
| 2 | `insertRear(20)` | 0 | 1 | `[10, 20, -, -, -]` | 20 added |
| 3 | `insertRear(30)` | 0 | 2 | `[10, 20, 30, -, -]` | 30 added |
| 4 | `deleteFront()` | 1 | 2 | `[-, 20, 30, -, -]` | Returns 10 |
| 5 | `deleteRear()` | 1 | 1 | `[-, 20, -, -, -]` | Returns 30 |

