## 3. Step-by-Step Implementation & Analytical Matrix

### 3.1 Master Program — Singly Linked List with All Operations

Below is the **complete, exam-ready C implementation** for KTU Module Experiment 2. Every line is commented to help you answer viva questions.

```c
#include <stdio.h>
#include <stdlib.h>

// STEP 1: Define the node structure
struct Node {
    int data;
    struct Node *next;
};

// STEP 2: Global head pointer
struct Node *head = NULL;

// ---------- INSERT AT BEGINNING ----------
void insertAtBeginning(int value) {
    struct Node *newNode = (struct Node *)malloc(sizeof(struct Node));
    newNode->data = value;
    newNode->next = head;   // New node points to old head
    head = newNode;          // Head now points to new node
    printf("%d inserted at beginning.\n", value);
}

// ---------- INSERT AT END ----------
void insertAtEnd(int value) {
    struct Node *newNode = (struct Node *)malloc(sizeof(struct Node));
    newNode->data = value;
    newNode->next = NULL;    // New node will be the last

    if (head == NULL) {
        head = newNode;
        return;
    }
    struct Node *temp = head;
    while (temp->next != NULL) {  // Traverse to last node
        temp = temp->next;
    }
    temp->next = newNode;         // Link last node to new node
    printf("%d inserted at end.\n", value);
}

// ---------- INSERT AT SPECIFIED POSITION ----------
void insertAtPosition(int value, int pos) {
    if (pos < 1) {
        printf("Invalid position.\n");
        return;
    }
    if (pos == 1) {
        insertAtBeginning(value);
        return;
    }
    struct Node *newNode = (struct Node *)malloc(sizeof(struct Node));
    newNode->data = value;
    struct Node *temp = head;
    for (int i = 1; i < pos - 1 && temp != NULL; i++) {
        temp = temp->next;          // Move to node just before target position
    }
    if (temp == NULL) {
        printf("Position out of range.\n");
        free(newNode);
        return;
    }
    newNode->next = temp->next;     // New node links to next node
    temp->next = newNode;           // Previous node links to new node
    printf("%d inserted at position %d.\n", value, pos);
}

// ---------- DELETE FROM BEGINNING ----------
void deleteFromBeginning() {
    if (head == NULL) {
        printf("List is empty.\n");
        return;
    }
    struct Node *temp = head;
    head = head->next;              // Move head to second node
    printf("%d deleted from beginning.\n", temp->data);
    free(temp);                     // Free old head's memory
}

// ---------- DELETE FROM END ----------
void deleteFromEnd() {
    if (head == NULL) {
        printf("List is empty.\n");
        return;
    }
    if (head->next == NULL) {       // Only one node
        printf("%d deleted from end.\n", head->data);
        free(head);
        head = NULL;
        return;
    }
    struct Node *temp = head;
    while (temp->next->next != NULL) {  // Stop at second-last node
        temp = temp->next;
    }
    printf("%d deleted from end.\n", temp->next->data);
    free(temp->next);               // Free last node
    temp->next = NULL;              // Mark new last node
}

// ---------- DELETE AT SPECIFIED POSITION ----------
void deleteAtPosition(int pos) {
    if (head == NULL || pos < 1) {
        printf("Invalid operation.\n");
        return;
    }
    if (pos == 1) {
        deleteFromBeginning();
        return;
    }
    struct Node *temp = head;
    for (int i = 1; i < pos - 1 && temp != NULL; i++) {
        temp = temp->next;          // Reach node before target
    }
    if (temp == NULL || temp->next == NULL) {
        printf("Position out of range.\n");
        return;
    }
    struct Node *toDelete = temp->next;  // Node to remove
    temp->next = toDelete->next;         // Bypass the node
    printf("%d deleted from position %d.\n", toDelete->data, pos);
    free(toDelete);                // Free removed node's memory
}

// ---------- DISPLAY / TRAVERSE ----------
void display() {
    if (head == NULL) {
        printf("List is empty.\n");
        return;
    }
    struct Node *temp = head;
    printf("List: ");
    while (temp != NULL) {
        printf("%d -> ", temp->data);
        temp = temp->next;
    }
    printf("NULL\n");
}

// ---------- SEARCH ----------
void search(int key) {
    struct Node *temp = head;
    int pos = 1;
    while (temp != NULL) {
        if (temp->data == key) {
            printf("%d found at position %d.\n", key, pos);
            return;
        }
        temp = temp->next;
        pos++;
    }
    printf("%d not found in the list.\n", key);
}

// ---------- COUNT NODES ----------
void countNodes() {
    int count = 0;
    struct Node *temp = head;
    while (temp != NULL) {
        count++;
        temp = temp->next;
    }
    printf("Total nodes: %d\n", count);
}

// ---------- REVERSE THE LIST ----------
void reverse() {
    struct Node *prev = NULL, *current = head, *next = NULL;
    while (current != NULL) {
        next = current->next;       // Store next node
        current->next = prev;       // Reverse the link
        prev = current;             // Move prev forward
        current = next;             // Move current forward
    }
    head = prev;                    // New head is old last node
    printf("List reversed.\n");
}

// ---------- MAIN ----------
int main() {
    int choice, value, pos;
    while (1) {
        printf("\n--- SINGLY LINKED LIST MENU ---\n");
        printf("1. Insert at Beginning\n2. Insert at End\n");
        printf("3. Insert at Position\n4. Delete from Beginning\n");
        printf("5. Delete from End\n6. Delete from Position\n");
        printf("7. Display\n8. Search\n9. Count Nodes\n");
        printf("10. Reverse\n11. Exit\n");
        printf("Enter choice: ");
        scanf("%d", &choice);

        switch (choice) {
            case 1: printf("Enter value: "); scanf("%d", &value);
                    insertAtBeginning(value); break;
            case 2: printf("Enter value: "); scanf("%d", &value);
                    insertAtEnd(value); break;
            case 3: printf("Enter value and position: ");
                    scanf("%d %d", &value, &pos);
                    insertAtPosition(value, pos); break;
            case 4: deleteFromBeginning(); break;
            case 5: deleteFromEnd(); break;
            case 6: printf("Enter position: "); scanf("%d", &pos);
                    deleteAtPosition(pos); break;
            case 7: display(); break;
            case 8: printf("Enter key: "); scanf("%d", &key); search(key); break;
            case 9: countNodes(); break;
            case 10: reverse(); break;
            case 11: exit(0);
            default: printf("Invalid choice.\n");
        }
    }
    return 0;
}
```

### 3.2 Dry Run — Insertion at Position (Analytical Matrix)

Consider list: `10 -> 20 -> 30 -> NULL` and we call `insertAtPosition(25, 3)`.

| Step | Action | State of List |
|---|---|---|
| 1 | Allocate `newNode` with data 25 | Memory allocated |
| 2 | Set `temp = head` (points to 10) | `temp → 10` |
| 3 | Loop iteration 1: `i=1`, move `temp = temp->next` | `temp → 20` |
| 4 | Exit loop (since `i=2` fails `i < pos-1 = 2`) | `temp → 20` |
| 5 | `newNode->next = temp->next` | newNode links to 30 |
| 6 | `temp->next = newNode` | 20 links to newNode |
| 7 | **Final List** | `10 → 20 → 25 → 30 → NULL` |
