## 3. Step-by-Step Derivations & Analytical Matrix

### 3.1 Exhaustive C Implementation of Circular Linked List Operations

Below is the **complete, runnable C program** for all required CLL operations as specified in the KTU 2024 Scheme Lab Manual.

```c
#include <stdio.h>
#include <stdlib.h>

// ---------- Node Definition ----------
struct Node {
    int data;
    struct Node *next;
};

// ---------- Create Circular Linked List ----------
struct Node* createCLL(int n) {
    struct Node *head = NULL, *temp = NULL, *newNode = NULL;
    int value, i;

    for (i = 0; i < n; i++) {
        printf("Enter data for node %d: ", i + 1);
        scanf("%d", &value);

        newNode = (struct Node*)malloc(sizeof(struct Node));
        newNode->data = value;
        newNode->next = NULL;

        if (head == NULL) {
            head = newNode;
            newNode->next = head;   // First node points to itself
            temp = head;
        } else {
            temp->next = newNode;
            newNode->next = head;   // Last node points to head
            temp = newNode;
        }
    }
    return head;
}

// ---------- Display (Traversal) ----------
void display(struct Node *head) {
    struct Node *temp = head;
    if (head == NULL) {
        printf("List is EMPTY.\n");
        return;
    }
    printf("Circular List: ");
    do {
        printf("%d -> ", temp->data);
        temp = temp->next;
    } while (temp != head);
    printf("(back to head)\n");
}

// ---------- Insert at Front ----------
struct Node* insertFront(struct Node *head, int value) {
    struct Node *newNode = (struct Node*)malloc(sizeof(struct Node));
    newNode->data = value;
    newNode->next = head;

    if (head == NULL) {
        newNode->next = newNode;   // Self-loop
        return newNode;
    }

    struct Node *temp = head;
    while (temp->next != head)     // Reach last node
        temp = temp->next;
    temp->next = newNode;          // Last node now points to new head
    return newNode;
}

// ---------- Insert at End ----------
struct Node* insertEnd(struct Node *head, int value) {
    struct Node *newNode = (struct Node*)malloc(sizeof(struct Node));
    newNode->data = value;
    newNode->next = head;

    if (head == NULL) {
        newNode->next = newNode;
        return newNode;
    }

    struct Node *temp = head;
    while (temp->next != head)
        temp = temp->next;
    temp->next = newNode;          // Old last now points to new node
    return head;
}

// ---------- Insert at Position k ----------
struct Node* insertAtPosition(struct Node *head, int value, int k) {
    if (k == 1) return insertFront(head, value);

    struct Node *newNode = (struct Node*)malloc(sizeof(struct Node));
    newNode->data = value;

    struct Node *temp = head;
    for (int i = 1; i < k - 1 && temp->next != head; i++)
        temp = temp->next;

    newNode->next = temp->next;
    temp->next = newNode;
    return head;
}

// ---------- Delete Front Node ----------
struct Node* deleteFront(struct Node *head) {
    if (head == NULL) {
        printf("List is EMPTY.\n");
        return NULL;
    }
    if (head->next == head) {      // Only one node
        free(head);
        return NULL;
    }
    struct Node *temp = head, *last = head;
    while (last->next != head)
        last = last->next;

    head = head->next;             // Move head
    last->next = head;             // Last points to new head
    free(temp);
    return head;
}

// ---------- Delete End Node ----------
struct Node* deleteEnd(struct Node *head) {
    if (head == NULL) {
        printf("List is EMPTY.\n");
        return NULL;
    }
    if (head->next == head) {
        free(head);
        return NULL;
    }
    struct Node *temp = head;
    while (temp->next->next != head)
        temp = temp->next;

    free(temp->next);
    temp->next = head;
    return head;
}

// ---------- Delete Node at Position k ----------
struct Node* deleteAtPosition(struct Node *head, int k) {
    if (head == NULL) {
        printf("List is EMPTY.\n");
        return NULL;
    }
    if (k == 1) return deleteFront(head);

    struct Node *temp = head;
    for (int i = 1; i < k - 1 && temp->next != head; i++)
        temp = temp->next;

    if (temp->next == head) {
        printf("Position out of range.\n");
        return head;
    }

    struct Node *toDelete = temp->next;
    temp->next = toDelete->next;
    free(toDelete);
    return head;
}

// ---------- Search Element ----------
int search(struct Node *head, int key) {
    if (head == NULL) return 0;
    struct Node *temp = head;
    do {
        if (temp->data == key) return 1;
        temp = temp->next;
    } while (temp != head);
    return 0;
}

// ---------- Main Function ----------
int main() {
    struct Node *head = NULL;
    int n, choice, value, k, key;

    printf("Enter number of nodes to create: ");
    scanf("%d", &n);
    head = createCLL(n);
    display(head);

    printf("\n1. Insert Front\n2. Insert End\n3. Insert at Position\n");
    printf("4. Delete Front\n5. Delete End\n6. Delete at Position\n");
    printf("7. Search\n8. Display\n9. Exit\n");

    while (1) {
        printf("\nEnter choice: ");
        scanf("%d", &choice);
        switch (choice) {
            case 1:
                printf("Enter value: "); scanf("%d", &value);
                head = insertFront(head, value);
                display(head); break;
            case 2:
                printf("Enter value: "); scanf("%d", &value);
                head = insertEnd(head, value);
                display(head); break;
            case 3:
                printf("Enter value and position: "); scanf("%d %d", &value, &k);
                head = insertAtPosition(head, value, k);
                display(head); break;
            case 4:
                head = deleteFront(head);
                display(head); break;
            case 5:
                head = deleteEnd(head);
                display(head); break;
            case 6:
                printf("Enter position: "); scanf("%d", &k);
                head = deleteAtPosition(head, k);
                display(head); break;
            case 7:
                printf("Enter key: "); scanf("%d", &key);
                printf(search(head, key) ? "Found\n" : "Not Found\n");
                break;
            case 8:
                display(head); break;
            case 9:
                exit(0);
            default:
                printf("Invalid choice.\n");
        }
    }
    return 0;
}
```

### 3.2 Step-by-Step Trace: Insertion at End

Let us trace inserting `value = 40` at the end of CLL: **10 → 20 → 30 → (back to 10)**

$$
\begin{aligned}
\text{Step 1:} \quad &\text{newNode} = \text{malloc}() \rightarrow \text{newNode.data} = 40, \; \text{newNode.next} = \text{NULL} \\
\text{Step 2:} \quad &\text{newNode.next} = \text{head} \quad \text{(set circular link)} \\
\text{Step 3:} \quad &\text{Traverse from head until temp.next} = \text{head} \\
&\text{temp stops at node containing 30} \\
\text{Step 4:} \quad &\text{temp.next} = \text{newNode} \quad \text{(re-route the old last)} \\
\text{Final State:} \quad &10 \rightarrow 20 \rightarrow 30 \rightarrow 40 \rightarrow \text{(back to 10)}
\end{aligned}
$$

